#include<bits/stdc++.h>
using namespace std;
vector<int> mp[50010];
int fa_bcj[50010],ans[50010];
int u[50010],v[50010];
int find(int x)
{
    return(x==fa_bcj[x]?x:fa_bcj[x]=find(fa_bcj[x]));
}
void merge(int x,int y)
{
    fa_bcj[find(x)]=find(y);
}
struct node
{
    int u,v,w;
    bool operator<(const node&b)const
    {
        return w<b.w;
    }
}e[50010];
int fa[50010][21],lg[50010],d[50010];
void dfs(int x,int f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        lg[i]=__lg(i);
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        u[i]=x;
        v[i]=y;
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&e[i].u,&e[i].v,&e[i].w);
    }
    sort(e+1,e+1+m);
    for(int i=1;i<=n;i++)
    {
        fa_bcj[i]=i;
        ans[i]=-1;
    }
    for(int i=1;i<=m;i++)
    {
        int x=find(e[i].u),y=find(e[i].v);
        int now=d[lca(e[i].u,e[i].v)];
        while(d[x]>now)
        {
            ans[x]=e[i].w;
            merge(x,fa[x][0]);
            x=find(x);
        }
        while(d[y]>now)
        {
            ans[y]=e[i].w;
            merge(y,fa[y][0]);
            y=find(y);
        }
    }
    for(int i=1;i<n;i++)
    {
        int x=u[i];
        if(d[v[i]]>d[u[i]])
        {
            x=v[i];
        }
        printf("%d\n",ans[x]);
    }
    return 0;
}
